import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";

import { doctors } from "../data/doctors";

const DoctorProfile = () => {
  const { doctorId } = useParams();

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 10 }}>
        <Typography variant="h4" align="center" color="error">
          Doctor not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 10 }}>           {/* ← changed to lg + more top/bottom padding */}
      <Paper
        elevation={6}
        sx={{
          p: 6,                                             // ← increased padding inside the card
          borderRadius: 4,
          backgroundColor: "#fafafa",                       // ← optional: light background
        }}
      >
        <Grid container spacing={6}>                        {/* ← more space between columns */}
          {/* Left column - photo + name */}
          <Grid item xs={12} md={5} sx={{ textAlign: "center" }}>  {/* ← wider left column */}
            <Avatar
              src={doctor.image}
              alt={doctor.name}
              sx={{
                width: 320,                                 // ← BIGGER PHOTO
                height: 320,
                mx: "auto",
                mb: 4,
                border: "4px solid #1976d2",                // ← nice border (optional)
                boxShadow: "0 8px 24px rgba(0,0,0,0.15)",   // ← shadow for depth
              }}
            />
            <Typography variant="h4" gutterBottom sx={{ fontWeight: "bold" }}>  {/* ← bigger name */}
              {doctor.name}
            </Typography>
            <Typography variant="h5" color="primary" gutterBottom>              {/* ← bigger specialty */}
              {doctor.specialty}
            </Typography>
          </Grid>

          {/* Right column - details */}
          <Grid item xs={12} md={7}>                        {/* ← wider right column */}
            <Typography variant="h5" gutterBottom sx={{ mb: 3, fontWeight: 600 }}>
              Professional Details
            </Typography>
            <Divider sx={{ mb: 3, borderColor: "#1976d2" }} />

            <List disablePadding>
              <ListItem sx={{ py: 2 }}>                     {/* ← more vertical spacing */}
                <ListItemText
                  primary={<Typography variant="h6">Experience</Typography>}
                  secondary={<Typography variant="body1">{doctor.experience}</Typography>}
                />
              </ListItem>
              <ListItem sx={{ py: 2 }}>
                <ListItemText
                  primary={<Typography variant="h6">Qualification</Typography>}
                  secondary={<Typography variant="body1">{doctor.qualification}</Typography>}
                />
              </ListItem>
              <ListItem sx={{ py: 2 }}>
                <ListItemText
                  primary={<Typography variant="h6">Availability</Typography>}
                  secondary={<Typography variant="body1">{doctor.availability}</Typography>}
                />
              </ListItem>
              <ListItem sx={{ py: 2, alignItems: "flex-start" }}>
                <ListItemText
                  primary={<Typography variant="h6">About</Typography>}
                  secondary={<Typography variant="body1" sx={{ lineHeight: 1.7 }}>{doctor.bio}</Typography>}
                />
              </ListItem>
            </List>

            <Box sx={{ mt: 6, textAlign: "center" }}>       {/* ← more space above button */}
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{
                  py: 2,
                  px: 6,
                  fontSize: "1.2rem",                       // ← bigger button text
                  borderRadius: 3,
                  boxShadow: "0 4px 20px rgba(25,118,210,0.3)",
                }}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
